struct PromoPayload: Equatable {
    let code: String
    let discountPercent: Int
}

enum PromoLinkError: Error, LocalizedError {
    case invalidHost
    case invalidPath
    case missingCode
    case invalidDiscount
    case discountOutOfRange

    var errorDescription: String? {
        switch self {
        case .invalidHost: return "Invalid host."
        case .invalidPath: return "Invalid path."
        case .missingCode: return "Missing promo code."
        case .invalidDiscount: return "Invalid discount."
        case .discountOutOfRange: return "Discount out of range (1...100)."
        }
    }
}

final class PromoLinkHandler {
    static let shared = PromoLinkHandler()

    private let allowedHosts: Set<String> = ["myapp.com", "www.myapp.com"]
    private let allowedPath = "/promo"

    @discardableResult
    func handle(url: URL) -> Bool {
        do {
            let payload = try parsePromo(url: url)
            UserAccountStore.shared.applyPromo(payload)
            PromoState.shared.set(
                status: "Applied",
                message: "Applied code \(payload.code) with \(payload.discountPercent)% discount."
            )
            return true
        } catch {
            PromoState.shared.set(status: "Error", message: (error as? LocalizedError)?.errorDescription ?? error.localizedDescription)
            return false
        }
    }

    func parsePromo(url: URL) throws -> PromoPayload {
        guard let host = url.host?.lowercased(), allowedHosts.contains(host) else {
            throw PromoLinkError.invalidHost
        }

        guard url.path == allowedPath else {
            throw PromoLinkError.invalidPath
        }

        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else {
            throw PromoLinkError.invalidDiscount
        }

        let items = components.queryItems ?? []
        let code = items.first(where: { $0.name.lowercased() == "code" })?.value?.trimmingCharacters(in: .whitespacesAndNewlines)
        guard let codeUnwrapped = code, !codeUnwrapped.isEmpty else {
            throw PromoLinkError.missingCode
        }

        let discountString = items.first(where: { $0.name.lowercased() == "discount" })?.value?.trimmingCharacters(in: .whitespacesAndNewlines)
        guard let discountStringUnwrapped = discountString,
              let discount = Int(discountStringUnwrapped)
        else {
            throw PromoLinkError.invalidDiscount
        }

        guard (1...100).contains(discount) else {
            throw PromoLinkError.discountOutOfRange
        }

        return PromoPayload(code: codeUnwrapped, discountPercent: discount)
    }
}

struct UserAccount: Equatable {
    let id: String
    var activePromoCode: String?
    var discountPercent: Int?
}

final class UserAccountStore {
    static let shared = UserAccountStore()

    private(set) var currentUser: UserAccount = UserAccount(id: "user_12345", activePromoCode: nil, discountPercent: nil)

    func applyPromo(_ promo: PromoPayload) {
        currentUser.activePromoCode = promo.code
        currentUser.discountPercent = promo.discountPercent
        NotificationCenter.default.post(name: .userAccountDidUpdate, object: nil)
    }

    func clearPromo() {
        currentUser.activePromoCode = nil
        currentUser.discountPercent = nil
        NotificationCenter.default.post(name: .userAccountDidUpdate, object: nil)
    }
}

extension Notification.Name {
    static let userAccountDidUpdate = Notification.Name("UserAccountStore.userAccountDidUpdate")
